const crypto = require('crypto');
const key = crypto.randomBytes(32);
const encryptedToken = crypto.createCipheriv('aes-256-cbc', key, Buffer.alloc(16)).update('your_token', 'utf8', 'hex');
const decryptedToken = crypto.createDecipheriv('aes-256-cbc', key, Buffer.alloc(16)).update(encryptedToken, 'hex', 'utf8');

